const { numero, nome, mensagem, areaAtual, msgCount } = $input.first().json;

const AREA_LABELS = {
  b2b: 'Soluções B2B', academico: 'Acadêmico & Pesquisa',
  observatorio: 'Observatório da Mulher', api: 'API & Integração',
  juridico: 'Assessoria Jurídica', filosofia: 'Filosofia & Teologia'
};

let nomeCompleto = nome, email = '', telefone = numero;

// Formato template: "nome: X\ne-mail: Y\ntelefone: Z"
const linhas = mensagem.split(/\n/);
for (const linha of linhas) {
  const l = linha.trim();
  const m = l.match(/^(nome|e-?mail|email|telefone|tel)\s*:\s*(.+)$/i);
  if (!m) continue;
  const chave = m[1].toLowerCase().replace(/-/g,'');
  const valor = m[2].trim();
  if (chave === 'nome' && valor.length > 1)                       nomeCompleto = valor;
  if ((chave === 'email' || chave === 'emal') && valor.includes('@')) email = valor.toLowerCase();
  if (chave === 'telefone' || chave === 'tel') {
    const digitos = valor.replace(/\D/g, '');
    // Normalizar: se 11 dígitos sem país, adicionar 55
    telefone = digitos.length >= 10 ? (digitos.startsWith('55') ? digitos : '55' + digitos) : numero;
  }
}

// Fallback: formato "Nome · email@..." (legado)
if (!email) {
  const emailMatch = mensagem.match(/[\w.+%-]+@[\w.-]+\.[a-zA-Z]{2,}/);
  if (emailMatch) {
    email = emailMatch[0].toLowerCase();
    const idx = mensagem.toLowerCase().indexOf(email);
    const antes = mensagem.substring(0, idx).replace(/[·•|,\s]+$/, '').trim();
    if (antes.length >= 3) nomeCompleto = antes;
  }
}

return [{ json: {
  _valido: email !== '',
  nomeCompleto, email, telefone,
  numero, nome, mensagem, areaAtual, msgCount,
  areaLabel: AREA_LABELS[areaAtual] || 'Jurídico'
} }];
